              </div>
              <div class="user-stat-divider"></div>
              <div class="user-stat-item">
                <span class="user-stat-num">{{ userTags.length }}</span>
                <span class="user-stat-label">标签</span>
              </div>
            </div>
          </div>
        </div>
      </el-col>

      <!-- 右侧编辑 -->
      <el-col :xs="24" :sm="24" :md="16">
        <!-- 编辑资料 -->
        <div class="profile-card">
          <div class="profile-card-header">
            <i class="el-icon-edit"></i>
            <span>编辑资料</span>
          </div>
          <el-form :model="editForm" label-width="70px">
            <el-row :gutter="20">
              <el-col :span="12">
                <el-form-item label="邮箱">
                  <el-input v-model="editForm.email" class="pi-input" />
                </el-form-item>
              </el-col>
              <el-col :span="12">
                <el-form-item label="手机">
                  <el-input v-model="editForm.phone" class="pi-input" />
                </el-form-item>
              </el-col>
            </el-row>
            <el-form-item>
              <el-button type="primary" class="pi-save-btn" @click="handleUpdate">
                <i class="el-icon-check"></i> 保存修改
              </el-button>
            </el-form-item>
          </el-form>
        </div>

        <!-- 技术标签 -->
        <div class="profile-card mt-20">
          <div class="profile-card-header">
            <i class="el-icon-collection-tag"></i>
            <span>技术标签 ({{ userTags.length }})</span>
          </div>
          <div class="tags-area">
            <div v-if="userTags.length === 0" class="tags-empty">
              <p>还没有添加技术标签</p>
              <p class="tags-hint">添加标签后，系统会为你推荐更精准的学习路径</p>
            </div>
            <template v-else>
              <span v-for="tag in userTags" :key="tag.id" class="user-tag">
                {{ tag.name }}
                <i class="el-icon-close tag-remove" @click="handleRemoveTag(tag.id)"></i>
              </span>
            </template>
            <button class="add-tag-btn" @click="showTagDialog = true">
              <i class="el-icon-plus"></i> 添加标签
            </button>
          </div>
        </div>

        <!-- 学习进度（占位） -->
        <div class="profile-card mt-20">
          <div class="profile-card-header">
            <i class="el-icon-notebook-2"></i>
            <span>学习进度</span>
          </div>
          <div class="progress-placeholder">
            <i class="el-icon-arrow-right"></i>
            <router-link to="/learning-paths" class="progress-link">浏览学习路径</router-link>
            <span>开始你的学习之旅</span>
          </div>
        </div>
      </el-col>
    </el-row>

    <!-- 添加标签对话框 -->
    <el-dialog title="添加技术标签" :visible.sync="showTagDialog" width="400px" top="30vh">
      <el-select v-model="selectedTagId" placeholder="选择标签" style="width: 100%">
        <el-option v-for="tag in allTags" :key="tag.id" :label="tag.name" :value="tag.id" />
      </el-select>
      <span slot="footer">
        <el-button @click="showTagDialog = false">取消</el-button>
        <el-button type="primary" @click="handleAddTag">确认</el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import { userApi, tagApi } from '../api';

export default {
  name: 'Profile',
  data() {
    return {
      userInfo: {},
      editForm: { nickname: '', email: '', phone: '' },
      userTags: [],
      allTags: [],
      showTagDialog: false,
      selectedTagId: null
    };
  },
  created() { this.loadData(); },
  methods: {
    async loadData() {
      try {
        const [userRes, tagRes, allTagRes] = await Promise.all([
          userApi.getUserInfo(),
          userApi.getTechTags(),
          tagApi.getAll()
        ]);
        if (userRes.code === 200) {
          this.userInfo = userRes.data;
          this.editForm = { ...userRes.data };
        }
        if (tagRes.code === 200) this.userTags = tagRes.data;
        if (allTagRes.code === 200) this.allTags = allTagRes.data;
      } catch {}
    },
    async handleUpdate() {
      const res = await userApi.updateUserInfo(this.editForm);
      if (res.code === 200) {
        this.$message.success('保存成功');
        this.loadData();
      }
    },
    async handleAddTag() {
      if (!this.selectedTagId) return;
      const res = await userApi.addTechTag(this.selectedTagId);
      if (res.code === 200) {
        this.$message.success('添加成功');
        this.showTagDialog = false;
        this.selectedTagId = null;
        this.loadData();
      }
    },
    async handleRemoveTag(tagId) {
      const res = await userApi.removeTechTag(tagId);
      if (res.code === 200) {
        this.$message.success('删除成功');
        this.loadData();
      }
    }
  }
};
</script>

